# ruff: noqa: E501
"""Static CSS and JavaScript assets for the COGANT dashboard.

These are extracted into a dedicated module to keep the main
:class:`cogant.viz.dashboard.DashboardGenerator` file small and to
make them easy to edit without scrolling through Python methods.

The generator's ``_generate_css`` and ``_generate_javascript``
methods are thin wrappers that return these constants unchanged,
so the rendered HTML is byte-identical to the pre-split version.
"""

DASHBOARD_CSS: str = "\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;\n            background: linear-gradient(135deg, #0f0f1e 0%, #1a1a2e 100%);\n            color: #e0e0e0;\n            line-height: 1.6;\n        }\n\n        .dashboard {\n            min-height: 100vh;\n            display: flex;\n            flex-direction: column;\n        }\n\n        header {\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            color: white;\n            padding: 40px 20px;\n            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);\n        }\n\n        header h1 {\n            font-size: 2.5em;\n            margin-bottom: 10px;\n        }\n\n        .header-meta {\n            display: flex;\n            gap: 20px;\n            font-size: 0.95em;\n            opacity: 0.9;\n        }\n\n        .container {\n            max-width: 1400px;\n            margin: 0 auto;\n            padding: 20px;\n            width: 100%;\n        }\n\n        .summary-cards {\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\n            gap: 20px;\n            margin: 30px 0;\n        }\n\n        .card {\n            background: linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%);\n            border: 1px solid rgba(102, 126, 234, 0.3);\n            padding: 20px;\n            border-radius: 8px;\n            backdrop-filter: blur(10px);\n        }\n\n        .card h3 {\n            color: #667eea;\n            font-size: 0.85em;\n            text-transform: uppercase;\n            letter-spacing: 1px;\n            margin-bottom: 10px;\n        }\n\n        .card-value {\n            font-size: 2em;\n            font-weight: bold;\n            color: #fff;\n        }\n\n        .card-subtext {\n            font-size: 0.85em;\n            color: #b0b0b0;\n            margin-top: 8px;\n        }\n\n        .tabs {\n            display: flex;\n            border-bottom: 2px solid rgba(102, 126, 234, 0.2);\n            background: rgba(0, 0, 0, 0.3);\n            overflow-x: auto;\n            padding: 0 20px;\n        }\n\n        .tab-button {\n            background: none;\n            border: none;\n            color: #b0b0b0;\n            padding: 15px 20px;\n            cursor: pointer;\n            font-size: 1em;\n            font-weight: 500;\n            border-bottom: 3px solid transparent;\n            transition: all 0.3s ease;\n            white-space: nowrap;\n        }\n\n        .tab-button:hover {\n            color: #667eea;\n        }\n\n        .tab-button.active {\n            color: #667eea;\n            border-bottom-color: #667eea;\n        }\n\n        .tab-content {\n            display: none;\n            padding: 30px 20px;\n            animation: fadeIn 0.3s ease;\n        }\n\n        .tab-content.active {\n            display: block;\n        }\n\n        @keyframes fadeIn {\n            from {\n                opacity: 0;\n                transform: translateY(10px);\n            }\n            to {\n                opacity: 1;\n                transform: translateY(0);\n            }\n        }\n\n        .chart-container {\n            background: rgba(20, 20, 30, 0.8);\n            border: 1px solid rgba(102, 126, 234, 0.2);\n            border-radius: 8px;\n            padding: 20px;\n            margin: 20px 0;\n        }\n\n        .chart-title {\n            color: #667eea;\n            font-size: 1.2em;\n            margin-bottom: 15px;\n            font-weight: 600;\n        }\n\n        svg {\n            max-width: 100%;\n            height: auto;\n        }\n\n        table {\n            width: 100%;\n            border-collapse: collapse;\n            background: rgba(20, 20, 30, 0.8);\n            border: 1px solid rgba(102, 126, 234, 0.2);\n            border-radius: 8px;\n            overflow: hidden;\n            margin: 20px 0;\n        }\n\n        th {\n            background: rgba(102, 126, 234, 0.1);\n            border-bottom: 2px solid rgba(102, 126, 234, 0.3);\n            padding: 15px;\n            text-align: left;\n            color: #667eea;\n            font-weight: 600;\n        }\n\n        td {\n            padding: 12px 15px;\n            border-bottom: 1px solid rgba(102, 126, 234, 0.1);\n        }\n\n        tr:hover {\n            background: rgba(102, 126, 234, 0.05);\n        }\n\n        .badge {\n            display: inline-block;\n            padding: 4px 12px;\n            border-radius: 20px;\n            font-size: 0.85em;\n            font-weight: 600;\n        }\n\n        .badge-pass {\n            background: rgba(76, 175, 80, 0.2);\n            color: #4caf50;\n            border: 1px solid rgba(76, 175, 80, 0.3);\n        }\n\n        .badge-fail {\n            background: rgba(244, 67, 54, 0.2);\n            color: #f44336;\n            border: 1px solid rgba(244, 67, 54, 0.3);\n        }\n\n        .badge-info {\n            background: rgba(33, 150, 243, 0.2);\n            color: #2196f3;\n            border: 1px solid rgba(33, 150, 243, 0.3);\n        }\n\n        .search-box {\n            background: rgba(20, 20, 30, 0.8);\n            border: 1px solid rgba(102, 126, 234, 0.2);\n            padding: 10px 15px;\n            border-radius: 6px;\n            color: #e0e0e0;\n            margin-bottom: 20px;\n            width: 100%;\n            max-width: 400px;\n        }\n\n        .search-box::placeholder {\n            color: #808080;\n        }\n\n        .mermaid {\n            background: rgba(20, 20, 30, 0.8);\n            border: 1px solid rgba(102, 126, 234, 0.2);\n            border-radius: 8px;\n            padding: 20px;\n            margin: 20px 0;\n            overflow-x: auto;\n        }\n\n        .validation-check {\n            display: flex;\n            align-items: center;\n            gap: 15px;\n            padding: 12px;\n            background: rgba(20, 20, 30, 0.5);\n            border-radius: 6px;\n            margin: 10px 0;\n        }\n\n        .validation-icon {\n            font-size: 1.5em;\n            flex-shrink: 0;\n        }\n\n        .confidence-bar {\n            background: linear-gradient(90deg, #4caf50, #ffc107, #f44336);\n            height: 8px;\n            border-radius: 4px;\n            margin-top: 5px;\n        }\n\n        .stat-distribution {\n            display: flex;\n            align-items: flex-end;\n            gap: 5px;\n            height: 150px;\n            margin: 20px 0;\n        }\n\n        .stat-bar {\n            flex: 1;\n            background: linear-gradient(180deg, #667eea 0%, #764ba2 100%);\n            border-radius: 4px 4px 0 0;\n            min-width: 20px;\n            position: relative;\n            transition: all 0.2s ease;\n        }\n\n        .stat-bar:hover {\n            opacity: 0.8;\n            box-shadow: 0 0 10px rgba(102, 126, 234, 0.5);\n        }\n\n        .stat-bar-label {\n            position: absolute;\n            bottom: -20px;\n            left: 50%;\n            transform: translateX(-50%);\n            font-size: 0.8em;\n            color: #b0b0b0;\n            white-space: nowrap;\n        }\n\n        .stat-bar-value {\n            position: absolute;\n            top: -20px;\n            left: 50%;\n            transform: translateX(-50%);\n            font-weight: bold;\n            color: #667eea;\n            font-size: 0.9em;\n        }\n\n        .grid-2 {\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(500px, 1fr));\n            gap: 20px;\n            margin: 20px 0;\n        }\n\n        .footer {\n            text-align: center;\n            padding: 30px 20px;\n            color: #808080;\n            font-size: 0.9em;\n            border-top: 1px solid rgba(102, 126, 234, 0.1);\n            margin-top: 40px;\n        }\n\n        .gantt-container {\n            position: relative;\n            height: 120px;\n            background: rgba(20, 20, 30, 0.8);\n            border: 1px solid rgba(102, 126, 234, 0.2);\n            border-radius: 8px;\n            margin: 20px 0;\n            padding: 20px 10px;\n        }\n\n        .gantt-header {\n            position: absolute;\n            left: 10px;\n            top: 5px;\n            font-size: 0.9em;\n            color: #667eea;\n            font-weight: bold;\n        }\n\n        .gantt-bar {\n            position: absolute;\n            top: 50px;\n            height: 40px;\n            border-radius: 4px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            opacity: 0.8;\n            transition: opacity 0.2s ease;\n            border: 1px solid rgba(255, 255, 255, 0.2);\n        }\n\n        .gantt-bar:hover {\n            opacity: 1;\n            box-shadow: 0 0 10px rgba(102, 126, 234, 0.4);\n        }\n\n        .gantt-label {\n            color: white;\n            font-size: 0.85em;\n            font-weight: bold;\n            text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.5);\n        }\n\n        @media (max-width: 768px) {\n            header h1 {\n                font-size: 1.8em;\n            }\n\n            .header-meta {\n                flex-direction: column;\n                gap: 5px;\n            }\n\n            .summary-cards {\n                grid-template-columns: 1fr;\n            }\n\n            .grid-2 {\n                grid-template-columns: 1fr;\n            }\n\n            .tabs {\n                padding: 0;\n            }\n\n            .tab-button {\n                padding: 12px 15px;\n                font-size: 0.9em;\n            }\n        }\n"

DASHBOARD_JS: str = "\n        // Initialize Mermaid\n        mermaid.initialize({ startOnLoad: true, theme: 'dark' });\n        mermaid.contentLoaded();\n\n        // Tab switching\n        function switchTab(event, tabId) {\n            event.preventDefault();\n\n            // Hide all tabs\n            const tabs = document.querySelectorAll('.tab-content');\n            tabs.forEach(tab => tab.classList.remove('active'));\n\n            // Deactivate all buttons\n            const buttons = document.querySelectorAll('.tab-button');\n            buttons.forEach(btn => btn.classList.remove('active'));\n\n            // Show selected tab\n            const selectedTab = document.getElementById(tabId);\n            if (selectedTab) {\n                selectedTab.classList.add('active');\n                event.target.classList.add('active');\n            }\n\n            // Re-render Mermaid in case diagrams are in this tab\n            setTimeout(() => {\n                mermaid.contentLoaded();\n            }, 100);\n        }\n\n        // Table filtering\n        function filterTable(input, tableId) {\n            const filter = input.value.toUpperCase();\n            const table = document.getElementById(tableId);\n            if (!table) return;\n\n            const rows = table.getElementsByTagName('tbody')[0].getElementsByTagName('tr');\n            for (let i = 0; i < rows.length; i++) {\n                const text = rows[i].textContent.toUpperCase();\n                rows[i].style.display = text.includes(filter) ? '' : 'none';\n            }\n        }\n\n        // Keyboard shortcut for tab switching (arrow keys)\n        document.addEventListener('keydown', function(event) {\n            if (event.key === 'ArrowRight' || event.key === 'ArrowLeft') {\n                const buttons = Array.from(document.querySelectorAll('.tab-button'));\n                const activeButton = document.querySelector('.tab-button.active');\n                const activeIndex = buttons.indexOf(activeButton);\n\n                let nextIndex;\n                if (event.key === 'ArrowRight') {\n                    nextIndex = (activeIndex + 1) % buttons.length;\n                } else {\n                    nextIndex = (activeIndex - 1 + buttons.length) % buttons.length;\n                }\n\n                const nextButton = buttons[nextIndex];\n                const tabId = nextButton.textContent.toLowerCase().replace(/\\s+/g, '-');\n                nextButton.click();\n            }\n        });\n"
